import type { StateCreator } from 'zustand';
import type { PointsProductsActions, PointsProductsState } from '../models';
import { PointsProductsStatus } from '../models';

export type PointsProductsSlice = {
  pointsProducts: PointsProductsState;
  pointsProductsActions: PointsProductsActions;
};

const initialPointsProductsState: PointsProductsState = {
  products: [],
  status: PointsProductsStatus.IDLE,
  error: undefined,
};

export const createPointsProductsSlice: StateCreator<
  PointsProductsSlice,
  [],
  [],
  PointsProductsSlice
> = set => ({
  pointsProducts: initialPointsProductsState,
  pointsProductsActions: {
    setStatus: status =>
      set(state => ({
        pointsProducts: {
          ...state.pointsProducts,
          status,
          ...(status === PointsProductsStatus.LOADING && {
            error: undefined,
          }),
        },
      })),
    setProducts: products =>
      set(state => ({
        pointsProducts: {
          ...state.pointsProducts,
          products,
          status: PointsProductsStatus.SUCCESS,
          error: undefined,
        },
      })),
    setError: error =>
      set(state => ({
        pointsProducts: {
          ...state.pointsProducts,
          error,
        },
      })),
    reset: () =>
      set({
        pointsProducts: initialPointsProductsState,
      }),
  },
});

